#include <stdio.h>
#include <stdbool.h>

bool isPalindrome(const char *s, int left, int right) {
    while (left < right) {
        if (s[left] != s[right]) return false;
        left++; right--;
    }
    return true;
}

bool validPalindrome(const char *s, int n) {
    int left = 0, right = n - 1;
    while (left < right) {
        if (s[left] == s[right]) {
            left++; right--; continue;
        }
        return isPalindrome(s, left + 1, right) || isPalindrome(s, left, right - 1);
    }
    return true;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        char s[105]; scanf("%s", s);
        printf("%s\n", validPalindrome(s, n) ? "true" : "false");
    }
    return 0;
}

