import java.io.*;
import java.util.*;

public class Main {
    private static boolean isPalindrome(char[] arr, int l, int r) {
        while (l < r) {
            if (arr[l] != arr[r]) return false;
            l++; r--;
        }
        return true;
    }
    private static boolean validPalindrome(char[] arr) {
        int l = 0, r = arr.length - 1;
        while (l < r) {
            if (arr[l] == arr[r]) { l++; r--; continue; }
            return isPalindrome(arr, l + 1, r) || isPalindrome(arr, l, r - 1);
        }
        return true;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int n = Integer.parseInt(br.readLine().trim());
            String s = br.readLine().trim();
            out.append(validPalindrome(s.toCharArray()) ? "true" : "false");
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

