import sys

def is_palindrome(s, l, r):
    while l < r:
        if s[l] != s[r]:
            return False
        l += 1
        r -= 1
    return True

def valid_palindrome(s):
    l, r = 0, len(s) - 1
    while l < r:
        if s[l] == s[r]:
            l += 1
            r -= 1
            continue
        return is_palindrome(s, l + 1, r) or is_palindrome(s, l, r - 1)
    return True

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        s = next(it)
        out.append('true' if valid_palindrome(s) else 'false')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

